(function () {
  'use strict';
  function addSkipLink() {
    if (document.querySelector('.skip-link')) return;
    var mainTarget = document.getElementById('main-content');
    if (!mainTarget) {
      mainTarget = document.querySelector('section#center') || document.querySelector('main') || document.querySelector('section');
      if (mainTarget) {
        mainTarget.id = 'main-content';
      }
    }
    if (!mainTarget) return;
    var skip = document.createElement('a');
    skip.className = 'skip-link';
    skip.href = '#main-content';
    skip.textContent = 'Skip to main content';
    document.body.insertBefore(skip, document.body.firstChild);
  }
  function enhanceExternalLinks() {
    var links = document.querySelectorAll('a[target="_blank"]');
    for (var i = 0; i < links.length; i += 1) {
      var rel = (links[i].getAttribute('rel') || '').toLowerCase();
      if (rel.indexOf('noopener') === -1 || rel.indexOf('noreferrer') === -1) {
        links[i].setAttribute('rel', 'noopener noreferrer');
      }
    }
  }
  function normalizeToTop() {
    var tops = document.querySelectorAll('#toTop');
    if (tops.length <= 1) return;
    for (var i = 1; i < tops.length; i += 1) {
      if (tops[i] && tops[i].parentNode) {
        tops[i].parentNode.removeChild(tops[i]);
      }
    }
  }
  function addHeaderScrollState() {
    var header = document.getElementById('header');
    if (!header) return;
    function onScroll() {
      if (window.scrollY > 8) {
        header.classList.add('is-scrolled');
      } else {
        header.classList.remove('is-scrolled');
      }
    }
    onScroll();
    window.addEventListener('scroll', onScroll, { passive: true });
  }
  function mobileNavAutoClose() {
    if (!window.jQuery) return;
    var $menu = window.jQuery('.navbar-collapse');
    if (!$menu.length) return;
    window.jQuery(document).on('click', '.navbar-collapse a', function () {
      if (window.innerWidth >= 768) return;
      if (window.jQuery(this).closest('.dropdown').length && window.jQuery(this).attr('href') === '#') {
        return;
      }
      $menu.collapse('hide');
    });
  }
  function ensureLazyImages() {
    var imgs = document.querySelectorAll('img:not([loading])');
    for (var i = 0; i < imgs.length; i += 1) {
      imgs[i].setAttribute('loading', 'lazy');
    }
  }
  function wireInstagramSections() {
    var headings = document.querySelectorAll('h3, h4, h5');
    var configuredPosts = Array.isArray(window.CHOCOCAM_INSTAGRAM_POSTS) ? window.CHOCOCAM_INSTAGRAM_POSTS : [];
    var fallbackProfile = window.CHOCOCAM_INSTAGRAM_PROFILE || 'https://www.instagram.com/';
    for (var i = 0; i < headings.length; i += 1) {
      var headingText = (headings[i].textContent || '').replace(/\s+/g, ' ').trim().toLowerCase();
      if (headingText.indexOf('instagram') === -1) {
        continue;
      }
      var scope = headings[i].closest('.footer_2i1') || headings[i].closest('.blog_d_page_r') || headings[i].parentElement;
      if (!scope) continue;
      var images = scope.querySelectorAll('img');
      var postIndex = 0;
      for (var j = 0; j < images.length; j += 1) {
        var img = images[j];
        var existingLink = img.closest('a');
        var targetUrl = img.getAttribute('data-post-url') || configuredPosts[postIndex] || fallbackProfile;
        if (!targetUrl) continue;
        postIndex += 1;
        if (existingLink) {
          existingLink.href = targetUrl;
          existingLink.target = '_blank';
          existingLink.rel = 'noopener noreferrer';
          existingLink.setAttribute('aria-label', 'Open Instagram post');
          continue;
        }
        var anchor = document.createElement('a');
        anchor.href = targetUrl;
        anchor.target = '_blank';
        anchor.rel = 'noopener noreferrer';
        anchor.setAttribute('aria-label', 'Open Instagram post');
        anchor.className = 'instagram-post-link';
        img.parentNode.insertBefore(anchor, img);
        anchor.appendChild(img);
      }
    }
  }
  function init() {
    addSkipLink();
    enhanceExternalLinks();
    normalizeToTop();
    addHeaderScrollState();
    mobileNavAutoClose();
    ensureLazyImages();
    wireInstagramSections();
  }
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init, { once: true });
  } else {
    init();
  }
})();
